  ('real-estate-moex-02872', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易法所稱結合，謂事業持有或取得他事業之股份或出資額，達到他事業有表決權股份或資本總額 多少比例以上者即屬之？', '["二分之一", "三分之一", "四分之一", "五分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02873', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '定型化契約中之一般條款牴觸非一般條款之約定者，下列那一部分契約條款無效？', '["僅非一般條款之牴觸部分無效", "僅一般條款之牴觸部分無效", "有關一般條款部分全部無效", "定型化契約全部條款均無效"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
