  ('real-estate-moex-02875', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '郵購或訪問買賣之消費者，對所收受之商品不願買受時，得於收商品後幾日內，退回商品或以書面通知 企業經營者解除買賣契約？', '["3日", "5日", "7日", "10日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02876', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列關於公平交易委員會職權行使之敘述，何者錯誤？', '["受政府之指示行使職權", "得依檢舉行使調查權", "調查處理時，得通知當事人及關係人到場陳述意見", "得派員前往事業之營業所進行調查"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02877', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關不動產經紀業之規定，何者有誤？', '["經紀業設立之營業處所至少應置經紀人1人", "非常態營業處所，其所銷售總金額達新台幣6億元以上時，該處所至少應置經紀人1人", "營業處所經紀營業員數每逾20名時，應增設經紀人1人", "經紀業應於經紀人到職之日起 1 個月內，造具名冊報請所在地主管機關層報中央主管機關備查，異動 時，亦同"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02878', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於消費訴訟之敘述，依消費者保護法之規定，下列何者錯誤？', '["訴訟管轄權專屬消費者住所地之法院", "法院為企業經營者敗訴之判決時，得依職權宣告減免擔保之假執行", "地方法院得設立消費專庭審理之", "地方法院之分院亦得設立消費專庭審理之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02879', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關不動產經紀業管理條例之規定，何者有誤？', '["不動產係指土地、土地定著物或房屋及其可移轉之權利", "房屋係指成屋、預售屋及其可移轉之權利", "成屋係指領有建造執照之建築物", "預售屋係指領有建造執照尚未建造完成而以將來完成之建築物為交易標的之物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02880', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '以下有關公平交易法之規定，何者有誤？', '["所稱交易相對人，係指與事業進行或成立交易之供給者或需求者", "所稱競爭，謂二以上事業在市場上以較有利之價格、數量、品質、服務或其他條件，爭取交易機會之 行為", "所稱獨占，謂事業在特定市場處於競爭狀態，不具有壓倒性地位，卻可排除競爭之能力者", "二以上事業，實際上不為價格之競爭，而其全體之對外關係，具有壓倒性地位，可排除競爭之能力者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02881', 'real-estate', 'real-estate-moex-096-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公寓大廈各區分所有權人係按何比例對建築物之共用部分及其基地有使用收益之權？', '["按其專有部分面積比例", "按其共有之應有部分比例", "按其基地共有部分面積比例", "按其專有部分及共有部分合計之面積比例"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "9416ba06c4a6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096250", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "096", "exam_name": "096年專技建築師、技師、法醫師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
